import React, { useEffect, useState } from 'react';
import { View, Text, FlatList, StyleSheet, ActivityIndicator, TouchableOpacity, Alert } from 'react-native';
import apiClient from '../api/client';

export default function HistoryScreen({ route }: any) {
  const { type, role } = route.params || { type: 'orders', role: 'CUSTOMER' };
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const endpoint = type === 'orders' ? '/orders' : '/bookings';
      const response = await apiClient.get(endpoint);
      setData(response.data);
    } catch (error) {
      console.error(`Failed to fetch ${type}`, error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [type]);

  const handleCompleteJob = async (id: string) => {
    try {
      await apiClient.patch(`/bookings/${id}/status`, { status: 'COMPLETED' });
      Alert.alert('Success', 'Job marked as completed!');
      fetchData(); // refresh list
    } catch (error) {
      console.error(error);
      Alert.alert('Error', 'Failed to update status.');
    }
  };

  if (loading) {
    return (
      <View style={styles.centered}>
        <ActivityIndicator size="large" color="#007AFF" />
      </View>
    );
  }

  const renderOrderItem = ({ item }: any) => (
    <View style={styles.card}>
      <View style={styles.cardHeader}>
        <Text style={styles.idText}>Order #{item.id.substring(0, 8)}</Text>
        <Text style={[styles.status, { color: item.status === 'PAID' ? '#28A745' : '#FF9500' }]}>
          {item.status}
        </Text>
      </View>
      <Text style={styles.date}>{new Date(item.createdAt).toLocaleDateString()}</Text>
      <Text style={styles.amount}>Total: ${item.totalAmount.toFixed(2)}</Text>
    </View>
  );

  const renderBookingItem = ({ item }: any) => (
    <View style={styles.card}>
      <View style={styles.cardHeader}>
        <Text style={styles.idText}>Booking #{item.id.substring(0, 8)}</Text>
        <Text style={[styles.status, { color: item.status === 'ACCEPTED' ? '#28A745' : '#007AFF' }]}>
          {item.status}
        </Text>
      </View>
      <Text style={styles.date}>Scheduled: {new Date(item.scheduledAt).toLocaleDateString()}</Text>
      <View style={styles.bookingFooter}>
        <Text style={styles.amount}>Service Total: ${item.totalPrice.toFixed(2)}</Text>
        {role === 'HANDYMAN' && item.status === 'ACCEPTED' && (
          <TouchableOpacity style={styles.completeBtn} onPress={() => handleCompleteJob(item.id)}>
            <Text style={styles.completeBtnText}>Complete Job</Text>
          </TouchableOpacity>
        )}
      </View>
    </View>
  );

  return (
    <View style={styles.container}>
      <FlatList
        data={data}
        keyExtractor={(item) => item.id}
        renderItem={type === 'orders' ? renderOrderItem : renderBookingItem}
        contentContainerStyle={styles.listContainer}
        ListEmptyComponent={
          <Text style={styles.emptyText}>You have no {type} yet.</Text>
        }
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F8F9FA',
  },
  centered: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  listContainer: {
    padding: 16,
  },
  card: {
    backgroundColor: '#FFFFFF',
    padding: 16,
    borderRadius: 12,
    marginBottom: 16,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.05,
    shadowRadius: 8,
    elevation: 2,
  },
  cardHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    marginBottom: 8,
  },
  idText: {
    fontSize: 14,
    fontWeight: 'bold',
    color: '#343A40',
  },
  status: {
    fontSize: 12,
    fontWeight: '700',
  },
  date: {
    fontSize: 14,
    color: '#6C757D',
    marginBottom: 8,
  },
  amount: {
    fontSize: 16,
    fontWeight: 'bold',
    color: '#212529',
  },
  bookingFooter: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginTop: 8,
  },
  completeBtn: {
    backgroundColor: '#28A745',
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderRadius: 8,
  },
  completeBtnText: {
    color: '#FFF',
    fontWeight: '600',
    fontSize: 12,
  },
  emptyText: {
    textAlign: 'center',
    marginTop: 40,
    fontSize: 16,
    color: '#888',
  },
});
