import React, { useContext, useState } from 'react';
import { View, Text, FlatList, StyleSheet, TouchableOpacity, ActivityIndicator, Alert } from 'react-native';
import { CartContext } from '../context/CartContext';
import { AuthContext } from '../context/AuthContext';
import apiClient from '../api/client';

export default function CartScreen({ navigation }: any) {
  const { cart, cartTotal, removeFromCart, updateQuantity } = useContext(CartContext);
  const { userInfo } = useContext(AuthContext);
  const [loading, setLoading] = useState(false);

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setLoading(true);
    try {
      const products = cart.filter(item => item.type === 'product').map(item => ({
        productId: item.id,
        quantity: item.quantity,
        price: item.price
      }));
      const response = await apiClient.post('/orders/checkout', {
        userId: userInfo?.id || 'dummy-user',
        totalAmount: cartTotal,
        paymentProvider: 'NONE',
        items: products
      });

      const orderId = response.data.order?.id || 'dummy-order';
      navigation.navigate('Checkout', { checkoutType: 'order', id: orderId, amount: cartTotal });
    } catch (error) {
      console.error(error);
      Alert.alert('Error', 'Failed to initialize checkout.');
    } finally {
      setLoading(false);
    }
  };

  if (cart.length === 0) {
    return (
      <View style={styles.centered}>
        <Text style={styles.emptyText}>Your cart is empty.</Text>
        <TouchableOpacity style={styles.browseButton} onPress={() => navigation.navigate('HomeTab')}>
          <Text style={styles.browseButtonText}>Browse items</Text>
        </TouchableOpacity>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <FlatList
        data={cart}
        keyExtractor={(item) => item.id}
        renderItem={({ item }) => (
          <View style={styles.card}>
            <View style={styles.itemInfo}>
              <Text style={styles.name}>{item.name}</Text>
              <Text style={styles.type}>{item.type === 'product' ? 'Product' : 'Service'}</Text>
              <Text style={styles.price}>${(item.price * item.quantity).toFixed(2)}</Text>
            </View>
            <View style={styles.actions}>
              <View style={styles.quantityContainer}>
                <TouchableOpacity onPress={() => updateQuantity(item.id, item.quantity - 1)} style={styles.qtyButton}>
                  <Text style={styles.qtyText}>-</Text>
                </TouchableOpacity>
                <Text style={styles.quantity}>{item.quantity}</Text>
                <TouchableOpacity onPress={() => updateQuantity(item.id, item.quantity + 1)} style={styles.qtyButton}>
                  <Text style={styles.qtyText}>+</Text>
                </TouchableOpacity>
              </View>
              <TouchableOpacity onPress={() => removeFromCart(item.id)} style={styles.removeBtn}>
                <Text style={styles.removeText}>Remove</Text>
              </TouchableOpacity>
            </View>
          </View>
        )}
      />
      <View style={styles.footer}>
        <View style={styles.totalRow}>
          <Text style={styles.totalLabel}>Total:</Text>
          <Text style={styles.totalPrice}>${cartTotal.toFixed(2)}</Text>
        </View>
        <TouchableOpacity 
          style={styles.checkoutButton}
          onPress={handleCheckout}
          disabled={loading}
        >
          {loading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.checkoutButtonText}>Proceed to Checkout</Text>
          )}
        </TouchableOpacity>
      </View>
    </View>
  );
}

