import axios from 'axios';
import { Platform } from 'react-native';

// Handle Android emulator localhost and iOS simulator localhost
const defaultBaseURL = Platform.OS === 'android' ? 'http://10.0.2.2:5000/api' : 'http://localhost:5000/api';
const baseURL = process.env.EXPO_PUBLIC_API_URL || defaultBaseURL;

const apiClient = axios.create({
  baseURL,
  headers: {
    'Content-Type': 'application/json',
  },
});

export default apiClient;
