import React, { useState } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, Alert, ActivityIndicator } from 'react-native';
import { useStripe } from '@stripe/stripe-react-native';
import apiClient from '../api/client';
import PaymentWebView from '../components/PaymentWebView';

export default function CheckoutScreen({ route, navigation }: any) {
  const { checkoutType = 'order', id = 'dummy-id', amount = 100 } = route.params || {};
  const [loadingProvider, setLoadingProvider] = useState<string | null>(null);
  const [paymentUrl, setPaymentUrl] = useState<string | null>(null);

  const { initPaymentSheet, presentPaymentSheet } = useStripe();

  const handleStripePayment = async () => {
    setLoadingProvider('STRIPE');
    try {
      const response = await apiClient.post('/payments/checkout', {
        checkoutType,
        id,
        provider: 'STRIPE',
      });
      const { clientSecret } = response.data;

      const initSheet = await initPaymentSheet({
        paymentIntentClientSecret: clientSecret,
        merchantDisplayName: 'Handyman E-commerce',
      });

      if (initSheet.error) {
        Alert.alert('Error', initSheet.error.message);
        setLoadingProvider(null);
        return;
      }

      const presentSheet = await presentPaymentSheet();
      if (presentSheet.error) {
        Alert.alert('Error', presentSheet.error.message);
      } else {
        Alert.alert('Success', 'Payment completed successfully!');
        navigation.navigate('HomeTab');
      }
    } catch (error) {
      console.error(error);
      Alert.alert('Payment failed', 'Could not initialize Stripe.');
    }
    setLoadingProvider(null);
  };

  const handleWebViewPayment = async (provider: 'PAYSTACK' | 'FLUTTERWAVE') => {
    setLoadingProvider(provider);
    try {
      const response = await apiClient.post('/payments/checkout', {
        checkoutType,
        id,
        provider,
      });

      if (provider === 'PAYSTACK') {
        setPaymentUrl(response.data.authorizationUrl);
      } else if (provider === 'FLUTTERWAVE') {
        setPaymentUrl(response.data.paymentLink);
      }
    } catch (error) {
      console.error(error);
      Alert.alert('Payment failed', `Could not initialize ${provider}.`);
      setLoadingProvider(null);
    }
  };

  if (paymentUrl) {
    return (
      <PaymentWebView
        url={paymentUrl}
        onPaymentSuccess={() => {
          setPaymentUrl(null);
          Alert.alert('Success', 'Payment completed successfully!');
          navigation.navigate('HomeTab');
        }}
        onPaymentCancel={() => {
          setPaymentUrl(null);
          Alert.alert('Cancelled', 'Payment was cancelled.');
        }}
      />
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Checkout</Text>
      <Text style={styles.amount}>Total: ${amount.toFixed(2)}</Text>

      <Text style={styles.subtitle}>Select Payment Method:</Text>

      <TouchableOpacity
        style={[styles.button, styles.stripeBtn]}
        onPress={handleStripePayment}
        disabled={loadingProvider !== null}
      >
        {loadingProvider === 'STRIPE' ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Pay with Stripe</Text>}
      </TouchableOpacity>

      <TouchableOpacity
        style={[styles.button, styles.paystackBtn]}
        onPress={() => handleWebViewPayment('PAYSTACK')}
        disabled={loadingProvider !== null}
      >
        {loadingProvider === 'PAYSTACK' ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Pay with Paystack</Text>}
      </TouchableOpacity>

      <TouchableOpacity
        style={[styles.button, styles.flutterwaveBtn]}
        onPress={() => handleWebViewPayment('FLUTTERWAVE')}
        disabled={loadingProvider !== null}
      >
        {loadingProvider === 'FLUTTERWAVE' ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Pay with Flutterwave</Text>}
      </TouchableOpacity>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    padding: 20,
    backgroundColor: '#fff',
    justifyContent: 'center',
  },
  title: {
    fontSize: 28,
    fontWeight: 'bold',
    textAlign: 'center',
    marginBottom: 10,
  },
  amount: {
    fontSize: 22,
    color: '#28a745',
    textAlign: 'center',
    marginBottom: 40,
  },
  subtitle: {
    fontSize: 18,
    marginBottom: 20,
    color: '#333',
  },
  button: {
    padding: 16,
    borderRadius: 8,
    marginBottom: 16,
    alignItems: 'center',
  },
  stripeBtn: {
    backgroundColor: '#635BFF',
  },
  paystackBtn: {
    backgroundColor: '#0ba4db',
  },
  flutterwaveBtn: {
    backgroundColor: '#f5a623',
  },
  buttonText: {
    color: '#fff',
    fontSize: 16,
    fontWeight: 'bold',
  },
});
