import React, { useEffect, useState, useContext } from 'react';
import { View, Text, FlatList, StyleSheet, ActivityIndicator, TouchableOpacity, Alert } from 'react-native';
import apiClient from '../api/client';
import { AuthContext } from '../context/AuthContext';

export default function ServicesScreen({ navigation }: any) {
  const [services, setServices] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [bookingLoading, setBookingLoading] = useState<string | null>(null);
  const { userInfo } = useContext(AuthContext);

  const handleBookService = async (service: any) => {
    if (!userInfo) {
      Alert.alert('Error', 'Please log in to book a service.');
      return;
    }
    setBookingLoading(service.id);
    try {
      const response = await apiClient.post('/bookings', {
        customerId: userInfo.id,
        serviceId: service.id,
        scheduledAt: new Date().toISOString(), // stub: scheduled immediately
        address: userInfo.address || 'User Address',
        totalPrice: service.basePrice,
      });

      navigation.navigate('Checkout', { 
        checkoutType: 'booking', 
        id: response.data.id, 
        amount: response.data.totalPrice 
      });
    } catch (error) {
      console.error(error);
      Alert.alert('Error', 'Failed to initialize booking.');
    } finally {
      setBookingLoading(null);
    }
  };

  useEffect(() => {
    const fetchServices = async () => {
      try {
        const response = await apiClient.get('/services');
        setServices(response.data);
      } catch (error) {
        console.error('Failed to fetch services', error);
      } finally {
        setLoading(false);
      }
    };

    fetchServices();
  }, []);

  if (loading) {
    return (
      <View style={styles.centered}>
        <ActivityIndicator size="large" color="#007AFF" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <FlatList
        data={services}
        keyExtractor={(item) => item.id}
        contentContainerStyle={styles.listContainer}
        renderItem={({ item }) => (
          <View style={styles.card}>
            <View style={styles.cardHeader}>
              <Text style={styles.name}>{item.name}</Text>
              <View style={styles.categoryBadge}>
                <Text style={styles.category}>{item.category}</Text>
              </View>
            </View>
            <Text style={styles.desc} numberOfLines={3}>{item.description}</Text>
            <View style={styles.footerRow}>
              <Text style={styles.price}>Base: ${item.basePrice.toFixed(2)}</Text>
              <TouchableOpacity 
                style={styles.bookButton} 
                onPress={() => handleBookService(item)}
                disabled={bookingLoading === item.id}
              >
                {bookingLoading === item.id ? (
                  <ActivityIndicator color="#fff" size="small" />
                ) : (
                  <Text style={styles.bookButtonText}>Book Now</Text>
                )}
              </TouchableOpacity>
            </View>
          </View>
        )}
        ListEmptyComponent={<Text style={styles.emptyText}>No services available.</Text>}
      />
    </View>
  );
}

